    """Show staged files."""
    index_path: str = os.path.join(".minigit", "index")
    with open(index_path, "r") as f:
        files: list[str] = [line.strip() for line in f if line.strip()]

    print("Staged files:")
    if not files:
        print("(none)")
    else:
        for fname in files:
            print(fname)


